import QRCode from 'qrcode.react'; 
import React, { useState, useEffect } from 'react';
import CurrentPatientCard from './CurrentPatientCard';
import UpcomingTokens from './UpcomingTokens';
import webSocketService from '../services/websocket';
import { patientApi } from '../services/api';
import '../styles/tvdisplay.css';

// In useEffect for WebSocket updates
webSocketService.connect((updatedQueue) => {
  setQueueData(updatedQueue);

  // Check if new patient is called
  if (updatedQueue.currentlyConsulting && 
      updatedQueue.currentlyConsulting.token !== queueData.currentlyConsulting?.token) {
    const patient = updatedQueue.currentlyConsulting;
    if (patient.isEmergency) {
      window.dispatchEvent(new CustomEvent('announce', { 
        detail: `Emergency patient ${patient.token}, please proceed immediately.` 
      }));
    } else {
      window.dispatchEvent(new CustomEvent('announce', { 
        detail: `Token Number ${patient.token}, ${patient.name}, please proceed to the consultation room.` 
      }));
    }
  }
});
const TVDisplay = () => {
  const [queueData, setQueueData] = useState({
    currentlyConsulting: null,
    waitingList: [],
    totalWaiting: 0
  });
  const [isFullscreen, setIsFullscreen] = useState(false);

  const fetchQueueData = async () => {
    try {
      const response = await patientApi.getQueue();
      setQueueData(response.data);
    } catch (error) {
      console.error('Error fetching queue data:', error);
    }
  };

  useEffect(() => {
    fetchQueueData();

    // Connect to WebSocket for real-time updates
    webSocketService.connect((updatedQueue) => {
      setQueueData(updatedQueue);
    });

    // Cleanup
    return () => {
      webSocketService.disconnect();
    };
  }, []);

  const toggleFullscreen = () => {
    if (!document.fullscreenElement) {
      document.documentElement.requestFullscreen();
      setIsFullscreen(true);
    } else {
      if (document.exitFullscreen) {
        document.exitFullscreen();
        setIsFullscreen(false);
      }
    }
  };

  useEffect(() => {
    const handleFullscreenChange = () => {
      setIsFullscreen(!!document.fullscreenElement);
    };

    document.addEventListener('fullscreenchange', handleFullscreenChange);
    return () => {
      document.removeEventListener('fullscreenchange', handleFullscreenChange);
    };
  }, []);

  return (
    <div className="tv-display">
      <button 
        className="fullscreen-toggle"
        onClick={toggleFullscreen}
      >
        {isFullscreen ? 'Exit Fullscreen' : 'Fullscreen'}
      </button>

      <div className="tv-content">
        <header className="tv-header">
          <h1>Queue Solved</h1>
          <div className="qr-section">
  <QRCode value="http:// 192.168.68.1:3000/self-register" size={120} />
  <p className="qr-label">Scan to Self Register</p>
</div>
          <div className="tv-clock">
            {new Date().toLocaleTimeString('en-US', { 
              hour: '2-digit', 
              minute: '2-digit',
              hour12: true 
            })}
          </div>
        </header>

        <div className="tv-main">
          <div className="tv-left">
            <CurrentPatientCard 
              patient={queueData.currentlyConsulting}
            />
          </div>

          <div className="tv-right">
            <UpcomingTokens 
              waitingList={queueData.waitingList}
              totalWaiting={queueData.totalWaiting}
            />
          </div>
        </div>

        <footer className="tv-footer">
          <div className="footer-message">
            Please wait for your turn. Thank you for your patience! 🙏
          </div>
          <div className="footer-info">
            Total patients in queue: {queueData.totalWaiting}
          </div>
        </footer>
      </div>
    </div>
  );
};
export default TVDisplay;
